      { id: 4, name: 'Fourth Year', subjects: 5, materials: 150 }
    ];
  } catch (error) {
    // Fallback mock data
    return [
      { id: 1, name: 'First Year', subjects: 8, materials: 200 },
      { id: 2, name: 'Second Year', subjects: 7, materials: 250 },
      { id: 3, name: 'Third Year', subjects: 6, materials: 300 },
